const pptxgen = require("pptxgenjs");

const pres = new pptxgen();
pres.layout = "LAYOUT_16x9";
pres.title = "공통업무 AI 침투율 제고 — 구성원 역량 향상 모델";

// ── 컬러 팔레트 (Midnight Executive 계열 커스텀) ──
const C = {
  navy:    "1A2B5C",   // 배경 메인
  navyMid: "243570",   // 카드 배경
  teal:    "0D9488",   // Layer 1 강조
  coral:   "C0533A",   // Layer 2 강조
  purple:  "6D3FA0",   // Layer 3 강조
  white:   "FFFFFF",
  offwhite:"E8EDF5",
  muted:   "9BAECC",
  gold:    "F0C040",
  dark:    "0F1A38",
};

// ─────────────────────────────────────────────
// SLIDE 1: 타이틀
// ─────────────────────────────────────────────
{
  const s = pres.addSlide();
  s.background = { color: C.navy };

  // 좌측 강조 바
  s.addShape(pres.shapes.RECTANGLE, {
    x: 0.55, y: 1.2, w: 0.08, h: 3.2,
    fill: { color: C.gold }, line: { color: C.gold }
  });

  // 메인 타이틀
  s.addText("공통업무 AI 침투율 제고", {
    x: 0.8, y: 1.2, w: 8.6, h: 0.9,
    fontSize: 38, bold: true, color: C.white,
    fontFace: "Arial Black", align: "left"
  });

  // 서브타이틀
  s.addText("구성원 역량 향상 3층 레이어 모델", {
    x: 0.8, y: 2.15, w: 8.6, h: 0.55,
    fontSize: 22, bold: false, color: C.gold,
    fontFace: "Arial", align: "left"
  });

  // 설명 라인
  s.addText("MS Copilot  ·  Lovable  ·  Antigravity  ·  워크플로우 재설계  ·  AX 내재화", {
    x: 0.8, y: 2.85, w: 8.6, h: 0.4,
    fontSize: 13, color: C.muted,
    fontFace: "Arial", align: "left"
  });

  // KPI 배너 (하단)
  s.addShape(pres.shapes.RECTANGLE, {
    x: 0, y: 4.6, w: 10, h: 1.03,
    fill: { color: C.dark }, line: { color: C.dark }
  });
  s.addText("참여율 85%   ·   생산성 10% 개선   ·   AX 성숙도 전사 평균 +15%", {
    x: 0.5, y: 4.65, w: 9, h: 0.9,
    fontSize: 15, color: C.gold, bold: true,
    fontFace: "Arial", align: "center", valign: "middle"
  });
}

// ─────────────────────────────────────────────
// SLIDE 2: 3층 레이어 전체 구조 Overview
// ─────────────────────────────────────────────
{
  const s = pres.addSlide();
  s.background = { color: C.navy };

  // 슬라이드 제목
  s.addText("3층 레이어 구조", {
    x: 0.5, y: 0.2, w: 9, h: 0.55,
    fontSize: 26, bold: true, color: C.white,
    fontFace: "Arial Black", align: "left", margin: 0
  });

  // ── Layer 1 블록 ──
  s.addShape(pres.shapes.RECTANGLE, {
    x: 0.5, y: 0.88, w: 9, h: 1.18,
    fill: { color: "0D3D5C" }, line: { color: C.teal, pt: 1.5 }
  });
  s.addShape(pres.shapes.RECTANGLE, {
    x: 0.5, y: 0.88, w: 0.12, h: 1.18,
    fill: { color: C.teal }, line: { color: C.teal }
  });
  s.addText("Layer 1 — 전사 공통 침투층", {
    x: 0.72, y: 0.9, w: 5, h: 0.38,
    fontSize: 15, bold: true, color: C.teal,
    fontFace: "Arial", align: "left", margin: 0
  });
  s.addText("MS Copilot · 별도 학습 없이 기존 업무 도구 안으로", {
    x: 0.72, y: 1.28, w: 8.5, h: 0.3,
    fontSize: 12, color: C.muted, fontFace: "Arial", margin: 0
  });
  // 3 chip
  const l1chips = ["Teams / Outlook  회의요약·이메일", "Word / Excel / PPT  Agent Mode", "AI 업무 침투  반복업무 대체"];
  l1chips.forEach((txt, i) => {
    s.addShape(pres.shapes.RECTANGLE, {
      x: 0.72 + i * 2.9, y: 1.6, w: 2.7, h: 0.34,
      fill: { color: "0A5070" }, line: { color: C.teal, pt: 0.8 }
    });
    s.addText(txt, {
      x: 0.72 + i * 2.9, y: 1.6, w: 2.7, h: 0.34,
      fontSize: 10.5, color: C.white, fontFace: "Arial",
      align: "center", valign: "middle"
    });
  });

  // 화살표 + 라벨
  s.addShape(pres.shapes.LINE, {
    x: 4.85, y: 2.1, w: 0, h: 0.3,
    line: { color: C.muted, width: 1.5 }
  });
  s.addText("▼  AI 친숙도 형성", {
    x: 3.5, y: 2.1, w: 3, h: 0.28,
    fontSize: 11, color: C.muted, fontFace: "Arial", align: "center"
  });

  // ── Layer 2 블록 ──
  s.addShape(pres.shapes.RECTANGLE, {
    x: 0.5, y: 2.38, w: 9, h: 1.18,
    fill: { color: "4A1C10" }, line: { color: C.coral, pt: 1.5 }
  });
  s.addShape(pres.shapes.RECTANGLE, {
    x: 0.5, y: 2.38, w: 0.12, h: 1.18,
    fill: { color: C.coral }, line: { color: C.coral }
  });
  s.addText("Layer 2 — 역량 심화층", {
    x: 0.72, y: 2.4, w: 5, h: 0.38,
    fontSize: 15, bold: true, color: C.coral,
    fontFace: "Arial", align: "left", margin: 0
  });
  s.addText("Lovable + Antigravity · 만드는 경험으로 전환", {
    x: 0.72, y: 2.78, w: 8.5, h: 0.3,
    fontSize: 12, color: C.muted, fontFace: "Arial", margin: 0
  });
  const l2chips = ["Lovable  미니앱 제작·체험", "Antigravity  에이전트 위임", "워크플로우 재설계  내 업무 AI로"];
  l2chips.forEach((txt, i) => {
    s.addShape(pres.shapes.RECTANGLE, {
      x: 0.72 + i * 2.9, y: 3.08, w: 2.7, h: 0.34,
      fill: { color: "6B2A18" }, line: { color: C.coral, pt: 0.8 }
    });
    s.addText(txt, {
      x: 0.72 + i * 2.9, y: 3.08, w: 2.7, h: 0.34,
      fontSize: 10.5, color: C.white, fontFace: "Arial",
      align: "center", valign: "middle"
    });
  });

  // 화살표
  s.addText("▼  설계자 전환 완료", {
    x: 3.5, y: 3.58, w: 3, h: 0.28,
    fontSize: 11, color: C.muted, fontFace: "Arial", align: "center"
  });

  // ── Layer 3 블록 ──
  s.addShape(pres.shapes.RECTANGLE, {
    x: 0.5, y: 3.86, w: 9, h: 1.1,
    fill: { color: "2D1450" }, line: { color: C.purple, pt: 1.5 }
  });
  s.addShape(pres.shapes.RECTANGLE, {
    x: 0.5, y: 3.86, w: 0.12, h: 1.1,
    fill: { color: C.purple }, line: { color: C.purple }
  });
  s.addText("Layer 3 — AX 내재화 · 조직 확산층", {
    x: 0.72, y: 3.88, w: 5.5, h: 0.38,
    fontSize: 15, bold: true, color: C.purple,
    fontFace: "Arial", align: "left", margin: 0
  });
  const l3chips = ["AX 쇼케이스  사례 공유", "팀 공통 Agent 개발  공유 자산", "AX 성숙도 측정  KPI 15%+"];
  l3chips.forEach((txt, i) => {
    s.addShape(pres.shapes.RECTANGLE, {
      x: 0.72 + i * 2.9, y: 4.28, w: 2.7, h: 0.56,
      fill: { color: "3D1A70" }, line: { color: C.purple, pt: 0.8 }
    });
    s.addText(txt, {
      x: 0.72 + i * 2.9, y: 4.28, w: 2.7, h: 0.56,
      fontSize: 10.5, color: C.white, fontFace: "Arial",
      align: "center", valign: "middle"
    });
  });
}

// ─────────────────────────────────────────────
// SLIDE 3: Layer 1 상세 — MS Copilot
// ─────────────────────────────────────────────
{
  const s = pres.addSlide();
  s.background = { color: C.navy };

  // 레이어 배지
  s.addShape(pres.shapes.RECTANGLE, {
    x: 0.5, y: 0.2, w: 2.2, h: 0.38,
    fill: { color: C.teal }, line: { color: C.teal }
  });
  s.addText("Layer 1  전사 공통 침투층", {
    x: 0.5, y: 0.2, w: 2.2, h: 0.38,
    fontSize: 10, bold: true, color: C.white,
    fontFace: "Arial", align: "center", valign: "middle"
  });

  s.addText("MS Copilot — 기존 도구 안으로 AI가 들어온다", {
    x: 0.5, y: 0.65, w: 9, h: 0.62,
    fontSize: 24, bold: true, color: C.white,
    fontFace: "Arial Black", align: "left", margin: 0
  });
  s.addText("별도 학습 없이, 지금 쓰는 Teams · Outlook · Word · Excel · PPT 안에서 AI 경험 시작", {
    x: 0.5, y: 1.28, w: 9, h: 0.35,
    fontSize: 13, color: C.muted, fontFace: "Arial"
  });

  // 3 카드
  const cards = [
    { title: "Teams / Outlook", items: ["회의 자동 요약", "이메일 초안 생성", "캘린더 인사이트"], color: "0A5070", border: C.teal },
    { title: "Word / Excel / PPT", items: ["Agent Mode 반복 편집", "데이터 분석 · 차트", "발표 자료 자동 생성"], color: "0A5070", border: C.teal },
    { title: "AI 업무 침투", items: ["반복업무 AI 대체 경험", "시간 측정으로 효과 확인", "AI 친숙도 · 신뢰 형성"], color: "0A5070", border: C.teal },
  ];
  cards.forEach((card, i) => {
    const cx = 0.5 + i * 3.08;
    s.addShape(pres.shapes.RECTANGLE, {
      x: cx, y: 1.75, w: 2.88, h: 3.3,
      fill: { color: card.color }, line: { color: card.border, pt: 1.5 }
    });
    s.addShape(pres.shapes.RECTANGLE, {
      x: cx, y: 1.75, w: 2.88, h: 0.46,
      fill: { color: card.border }, line: { color: card.border }
    });
    s.addText(card.title, {
      x: cx, y: 1.75, w: 2.88, h: 0.46,
      fontSize: 13, bold: true, color: C.white,
      fontFace: "Arial", align: "center", valign: "middle"
    });
    s.addText(card.items.map(t => t).join("\n"), {
      x: cx + 0.15, y: 2.28, w: 2.58, h: 2.6,
      fontSize: 12.5, color: C.offwhite, fontFace: "Arial",
      bullet: false, valign: "top",
    });
    // 수동 bullet
    card.items.forEach((item, j) => {
      s.addShape(pres.shapes.OVAL, {
        x: cx + 0.18, y: 2.35 + j * 0.72, w: 0.1, h: 0.1,
        fill: { color: card.border }, line: { color: card.border }
      });
      s.addText(item, {
        x: cx + 0.35, y: 2.28 + j * 0.72, w: 2.35, h: 0.4,
        fontSize: 12, color: C.offwhite, fontFace: "Arial", valign: "middle"
      });
    });
  });

  // 하단 핵심 원리
  s.addShape(pres.shapes.RECTANGLE, {
    x: 0.5, y: 5.1, w: 9, h: 0.42,
    fill: { color: C.dark }, line: { color: C.dark }
  });
  s.addText("핵심 원리 : 도구를 바꾸는 것이 아니라, 기존 도구의 사용 방식을 AI로 전환한다", {
    x: 0.5, y: 5.1, w: 9, h: 0.42,
    fontSize: 12, color: C.gold, fontFace: "Arial",
    align: "center", valign: "middle", italic: true
  });
}

// ─────────────────────────────────────────────
// SLIDE 4: Layer 2 상세 — 역량 심화
// ─────────────────────────────────────────────
{
  const s = pres.addSlide();
  s.background = { color: C.navy };

  s.addShape(pres.shapes.RECTANGLE, {
    x: 0.5, y: 0.2, w: 2.2, h: 0.38,
    fill: { color: C.coral }, line: { color: C.coral }
  });
  s.addText("Layer 2  역량 심화층", {
    x: 0.5, y: 0.2, w: 2.2, h: 0.38,
    fontSize: 10, bold: true, color: C.white,
    fontFace: "Arial", align: "center", valign: "middle"
  });

  s.addText("만드는 경험 — 사용자에서 설계자로", {
    x: 0.5, y: 0.65, w: 9, h: 0.62,
    fontSize: 24, bold: true, color: C.white,
    fontFace: "Arial Black", align: "left", margin: 0
  });
  s.addText("Lovable + Antigravity로 직접 만들어보는 경험이 AI 역량의 실질적 전환점이 된다", {
    x: 0.5, y: 1.28, w: 9, h: 0.35,
    fontSize: 13, color: C.muted, fontFace: "Arial"
  });

  const cards = [
    { title: "Lovable", sub: "미니앱 제작 · 체험 진입", items: ["HR 업무용 미니앱 직접 생성", "코드 없이 결과물 완성 경험", "완성 경험이 심리적 전환점"], color: "5A1C10", border: C.coral },
    { title: "Antigravity", sub: "에이전트 위임 · GUI 기반", items: ["Manager View로 에이전트 지시", "병렬 작업 시각적 관리", "비개발자 친화적 인터페이스"], color: "5A1C10", border: C.coral },
    { title: "워크플로우 재설계", sub: "내 업무를 AI로 다시 그리기", items: ["업무 Before/After 10주 실습", "시간 측정 → 숫자로 효과 확인", "팀 공유로 행동 전염 유도"], color: "5A1C10", border: C.coral },
  ];
  cards.forEach((card, i) => {
    const cx = 0.5 + i * 3.08;
    s.addShape(pres.shapes.RECTANGLE, {
      x: cx, y: 1.75, w: 2.88, h: 3.6,
      fill: { color: card.color }, line: { color: card.border, pt: 1.5 }
    });
    s.addShape(pres.shapes.RECTANGLE, {
      x: cx, y: 1.75, w: 2.88, h: 0.46,
      fill: { color: card.border }, line: { color: card.border }
    });
    s.addText(card.title, {
      x: cx, y: 1.75, w: 2.88, h: 0.46,
      fontSize: 13, bold: true, color: C.white,
      fontFace: "Arial", align: "center", valign: "middle"
    });
    s.addText(card.sub, {
      x: cx + 0.1, y: 2.24, w: 2.68, h: 0.32,
      fontSize: 11, color: C.gold, fontFace: "Arial",
      align: "center", italic: true
    });
    card.items.forEach((item, j) => {
      s.addShape(pres.shapes.OVAL, {
        x: cx + 0.18, y: 2.68 + j * 0.78, w: 0.1, h: 0.1,
        fill: { color: card.border }, line: { color: card.border }
      });
      s.addText(item, {
        x: cx + 0.35, y: 2.61 + j * 0.78, w: 2.35, h: 0.45,
        fontSize: 11.5, color: C.offwhite, fontFace: "Arial", valign: "middle"
      });
    });
  });

  s.addShape(pres.shapes.RECTANGLE, {
    x: 0.5, y: 5.1, w: 9, h: 0.42,
    fill: { color: C.dark }, line: { color: C.dark }
  });
  s.addText("핵심 원리 : 도구를 배우는 것이 아니라, 내 업무의 어느 부분이 나여야 하는지를 다시 정의한다", {
    x: 0.5, y: 5.1, w: 9, h: 0.42,
    fontSize: 11.5, color: C.gold, fontFace: "Arial",
    align: "center", valign: "middle", italic: true
  });
}

// ─────────────────────────────────────────────
// SLIDE 5: Layer 3 상세 — AX 내재화 확산
// ─────────────────────────────────────────────
{
  const s = pres.addSlide();
  s.background = { color: C.navy };

  s.addShape(pres.shapes.RECTANGLE, {
    x: 0.5, y: 0.2, w: 2.5, h: 0.38,
    fill: { color: C.purple }, line: { color: C.purple }
  });
  s.addText("Layer 3  AX 내재화 · 조직 확산층", {
    x: 0.5, y: 0.2, w: 2.5, h: 0.38,
    fontSize: 10, bold: true, color: C.white,
    fontFace: "Arial", align: "center", valign: "middle"
  });

  s.addText("개인 역량 → 팀 자산 → 조직 문화", {
    x: 0.5, y: 0.65, w: 9, h: 0.62,
    fontSize: 24, bold: true, color: C.white,
    fontFace: "Arial Black", align: "left", margin: 0
  });
  s.addText("구성원이 재설계한 워크플로우가 팀 공유 자산이 되고, AX 문화의 씨앗이 된다", {
    x: 0.5, y: 1.28, w: 9, h: 0.35,
    fontSize: 13, color: C.muted, fontFace: "Arial"
  });

  const cards = [
    { title: "AX 쇼케이스", sub: "구성원 재설계 사례 공유", items: ["10주 스프린트 결과 발표", "Before/After 수치 공개", "행동 전염 효과 유도"], color: "2D1450", border: C.purple },
    { title: "팀 공통 Agent 개발", sub: "반복업무 자동화 공유 자산", items: ["개인 자동화 → 팀 자산 전환", "공통 프롬프트 템플릿 구축", "EXG 팀 AI 워크플로우 라이브러리"], color: "2D1450", border: C.purple },
    { title: "AX 성숙도 측정", sub: "KPI 15% 초과 · 전사 확산", items: ["참여율 85% 달성 추적", "생산성 10% 개선 정량 측정", "전사 AX 성숙도 평균 +15%"], color: "2D1450", border: C.purple },
  ];
  cards.forEach((card, i) => {
    const cx = 0.5 + i * 3.08;
    s.addShape(pres.shapes.RECTANGLE, {
      x: cx, y: 1.75, w: 2.88, h: 3.6,
      fill: { color: card.color }, line: { color: card.border, pt: 1.5 }
    });
    s.addShape(pres.shapes.RECTANGLE, {
      x: cx, y: 1.75, w: 2.88, h: 0.46,
      fill: { color: card.border }, line: { color: card.border }
    });
    s.addText(card.title, {
      x: cx, y: 1.75, w: 2.88, h: 0.46,
      fontSize: 13, bold: true, color: C.white,
      fontFace: "Arial", align: "center", valign: "middle"
    });
    s.addText(card.sub, {
      x: cx + 0.1, y: 2.24, w: 2.68, h: 0.32,
      fontSize: 11, color: C.gold, fontFace: "Arial",
      align: "center", italic: true
    });
    card.items.forEach((item, j) => {
      s.addShape(pres.shapes.OVAL, {
        x: cx + 0.18, y: 2.68 + j * 0.78, w: 0.1, h: 0.1,
        fill: { color: card.border }, line: { color: card.border }
      });
      s.addText(item, {
        x: cx + 0.35, y: 2.61 + j * 0.78, w: 2.35, h: 0.45,
        fontSize: 11.5, color: C.offwhite, fontFace: "Arial", valign: "middle"
      });
    });
  });

  s.addShape(pres.shapes.RECTANGLE, {
    x: 0.5, y: 5.1, w: 9, h: 0.42,
    fill: { color: C.dark }, line: { color: C.dark }
  });
  s.addText("핵심 원리 : 한 명의 가시적 성공 사례가 열 번의 교육보다 강력하다", {
    x: 0.5, y: 5.1, w: 9, h: 0.42,
    fontSize: 12, color: C.gold, fontFace: "Arial",
    align: "center", valign: "middle", italic: true
  });
}

// ─────────────────────────────────────────────
// SLIDE 6: 10주 워크플로우 재설계 실습 로드맵
// ─────────────────────────────────────────────
{
  const s = pres.addSlide();
