const pptxgen = require("pptxgenjs");

const pres = new pptxgen();
pres.layout = "LAYOUT_16x9";
pres.title = "공통업무 AI 침투율 제고 — 구성원 역량 향상";

// ── 맥킨지 + LG 컬러 팔레트 ──────────────────────────
const C = {
  white:   "FFFFFF",
  black:   "1A1A1A",
  gray1:   "404040",  // 본문
  gray2:   "767676",  // 보조 텍스트
  gray3:   "BBBBBB",  // 구분선
  gray4:   "F4F4F4",  // 배경 칸
  lgRed:   "A50034",  // LG 레드 — 강조 유일
  lgRedL:  "F2DEDF",  // LG 레드 연한 fill
  navy:    "1D3557",  // 제목 보조
  chartB1: "1D3557",  // 차트 진한 바
  chartB2: "A8C8E8",  // 차트 연한 바
};

// ── 슬라이드 공통 헬퍼 ──────────────────────────────
function addHeader(s, title, subtitle) {
  // 상단 LG 레드 가는 선
  s.addShape(pres.shapes.RECTANGLE, {
    x: 0, y: 0, w: 10, h: 0.06,
    fill: { color: C.lgRed }, line: { color: C.lgRed }
  });
  // Action Title
  s.addText(title, {
    x: 0.55, y: 0.16, w: 8.9, h: 0.62,
    fontSize: 20, bold: true, color: C.black,
    fontFace: "Arial", align: "left", margin: 0
  });
  if (subtitle) {
    s.addText(subtitle, {
      x: 0.55, y: 0.78, w: 8.9, h: 0.3,
      fontSize: 11, color: C.gray2,
      fontFace: "Arial", align: "left", margin: 0
    });
  }
  // 제목 구분선
  s.addShape(pres.shapes.LINE, {
    x: 0.55, y: 1.08, w: 8.9, h: 0,
    line: { color: C.gray3, width: 0.5 }
  });
}

function addFooter(s, source) {
  s.addShape(pres.shapes.LINE, {
    x: 0.55, y: 5.22, w: 8.9, h: 0,
    line: { color: C.gray3, width: 0.5 }
  });
  s.addText(source || "LG PRI HR실 EXG팀 · 2026", {
    x: 0.55, y: 5.26, w: 8.9, h: 0.28,
    fontSize: 9, color: C.gray2,
    fontFace: "Arial", align: "right", margin: 0
  });
}

// ─────────────────────────────────────────────────────
// SLIDE 1: 표지
// ─────────────────────────────────────────────────────
{
  const s = pres.addSlide();
  s.background = { color: C.white };

  s.addShape(pres.shapes.RECTANGLE, {
    x: 0, y: 0, w: 10, h: 0.1,
    fill: { color: C.lgRed }, line: { color: C.lgRed }
  });

  // 왼쪽 세로 강조 바
  s.addShape(pres.shapes.RECTANGLE, {
    x: 0.55, y: 1.4, w: 0.07, h: 2.6,
    fill: { color: C.lgRed }, line: { color: C.lgRed }
  });

  s.addText("공통업무 AI 침투율 제고", {
    x: 0.78, y: 1.4, w: 8.2, h: 0.82,
    fontSize: 34, bold: true, color: C.black,
    fontFace: "Arial", align: "left", margin: 0
  });
  s.addText("구성원 역량 향상 전략", {
    x: 0.78, y: 2.24, w: 8.2, h: 0.55,
    fontSize: 24, bold: false, color: C.gray1,
    fontFace: "Arial", align: "left", margin: 0
  });
  s.addText("3층 레이어 모델 · 10주 스프린트 · AX 성숙도 KPI", {
    x: 0.78, y: 2.88, w: 8.2, h: 0.36,
    fontSize: 13, color: C.gray2,
    fontFace: "Arial", align: "left", margin: 0
  });

  // 하단 메타
  s.addShape(pres.shapes.LINE, {
    x: 0.55, y: 3.7, w: 8.9, h: 0,
    line: { color: C.gray3, width: 0.5 }
  });
  s.addText("LG PRI HR실 EXG팀  |  2026. 03", {
    x: 0.55, y: 3.82, w: 4, h: 0.3,
    fontSize: 11, color: C.gray2,
    fontFace: "Arial", align: "left", margin: 0
  });

  // 우측 KPI 3개 요약
  const kpis = [
    { num: "85%", lbl: "구성원 참여율" },
    { num: "10%", lbl: "생산성 개선" },
    { num: "+15%", lbl: "AX 성숙도 전사 평균 대비" },
  ];
  kpis.forEach((k, i) => {
    const bx = 5.8 + i * 1.45;
    s.addText(k.num, {
      x: bx, y: 3.72, w: 1.3, h: 0.5,
      fontSize: 22, bold: true, color: C.lgRed,
      fontFace: "Arial", align: "center", margin: 0
    });
    s.addText(k.lbl, {
      x: bx, y: 4.22, w: 1.3, h: 0.3,
      fontSize: 8.5, color: C.gray2,
      fontFace: "Arial", align: "center", margin: 0
    });
  });
}

// ─────────────────────────────────────────────────────
// SLIDE 2: 전략 요약 — 3층 구조 논리
// ─────────────────────────────────────────────────────
{
  const s = pres.addSlide();
  s.background = { color: C.white };

  addHeader(s,
    "AI 침투율 제고는 단계적 역량 전환으로 달성된다 — 3층 레이어 구조",
    "도구 학습이 아닌 일하는 방식의 전환이 목표"
  );
  addFooter(s);

  // 3개 레이어 수평 블록
  const layers = [
    {
      tag: "Layer 1",
      title: "전사 공통\n침투층",
      sub: "MS Copilot",
      body: "기존 Teams·Outlook·Word·Excel·PPT 안에서 AI 경험 시작\n별도 학습 없이 AI 친숙도 형성",
      kpi: "저항 최소화",
      color: C.navy,
      light: "E8EDF5",
    },
    {
      tag: "Layer 2",
      title: "역량\n심화층",
      sub: "Lovable + Antigravity",
      body: "직접 만드는 경험으로 전환\n미니앱 제작, 에이전트 위임 실습\n10주 워크플로우 재설계 스프린트",
      kpi: "설계자 전환",
      color: "7A5C00",
      light: "FFF8DC",
    },
    {
      tag: "Layer 3",
      title: "AX 내재화\n확산층",
      sub: "팀 공통 Agent · 쇼케이스",
      body: "개인 역량 → 팀 공유 자산\nAX 쇼케이스로 행동 전염 유도\nKPI 측정 및 전사 확산",
      kpi: "조직 문화",
      color: "4A1C6A",
      light: "F3E8FF",
    },
  ];

  layers.forEach((L, i) => {
    const bx = 0.55 + i * 3.05;
    // 배경 박스
    s.addShape(pres.shapes.RECTANGLE, {
      x: bx, y: 1.22, w: 2.85, h: 3.8,
      fill: { color: L.light }, line: { color: C.gray3, pt: 0.5 }
    });
    // 상단 컬러 바
    s.addShape(pres.shapes.RECTANGLE, {
      x: bx, y: 1.22, w: 2.85, h: 0.38,
      fill: { color: L.color }, line: { color: L.color }
    });
    // 레이어 태그
    s.addText(L.tag, {
      x: bx + 0.12, y: 1.22, w: 1.5, h: 0.38,
      fontSize: 10, bold: true, color: C.white,
      fontFace: "Arial", align: "left", valign: "middle", margin: 0
    });
    // KPI 배지 (우측)
    s.addShape(pres.shapes.RECTANGLE, {
      x: bx + 1.85, y: 1.28, w: 0.88, h: 0.26,
      fill: { color: C.white }, line: { color: C.white }
    });
    s.addText(L.kpi, {
      x: bx + 1.85, y: 1.28, w: 0.88, h: 0.26,
      fontSize: 9, bold: true, color: L.color,
      fontFace: "Arial", align: "center", valign: "middle", margin: 0
    });
    // 타이틀
    s.addText(L.title, {
      x: bx + 0.15, y: 1.66, w: 2.55, h: 0.7,
      fontSize: 16, bold: true, color: C.black,
      fontFace: "Arial", align: "left", margin: 0
    });
    // 도구명
    s.addText(L.sub, {
      x: bx + 0.15, y: 2.36, w: 2.55, h: 0.3,
      fontSize: 10, color: L.color, bold: true,
      fontFace: "Arial", align: "left", margin: 0
    });
    // 구분선
    s.addShape(pres.shapes.LINE, {
      x: bx + 0.15, y: 2.68, w: 2.55, h: 0,
      line: { color: C.gray3, width: 0.5 }
    });
    // 본문
    const lines = L.body.split("\n");
    lines.forEach((line, j) => {
      s.addShape(pres.shapes.OVAL, {
        x: bx + 0.18, y: 2.82 + j * 0.54, w: 0.08, h: 0.08,
        fill: { color: L.color }, line: { color: L.color }
      });
      s.addText(line, {
        x: bx + 0.32, y: 2.75 + j * 0.54, w: 2.38, h: 0.42,
        fontSize: 11, color: C.gray1,
        fontFace: "Arial", align: "left", valign: "middle", margin: 0
      });
    });
  });

  // 화살표 연결
  s.addText("→", {
    x: 3.28, y: 2.85, w: 0.32, h: 0.4,
    fontSize: 16, color: C.gray3, fontFace: "Arial", align: "center"
  });
  s.addText("→", {
    x: 6.33, y: 2.85, w: 0.32, h: 0.4,
    fontSize: 16, color: C.gray3, fontFace: "Arial", align: "center"
  });
}

// ─────────────────────────────────────────────────────
// SLIDE 3: Layer 1 — MS Copilot 침투 전략
// ─────────────────────────────────────────────────────
{
  const s = pres.addSlide();
  s.background = { color: C.white };

  addHeader(s,
    "MS Copilot은 기존 도구 안에 AI를 침투시켜 구성원 저항을 구조적으로 제거한다",
    "도구를 바꾸는 것이 아니라, 기존 도구의 사용 방식을 AI로 전환"
  );
  addFooter(s, "Source: Microsoft 365 Wave 3 발표 (2026.03) / Irrational Labs AI Adoption Research (2025)");

  // 왼쪽: 3가지 도구별 기능
  const tools = [
    { name: "Teams / Outlook", items: ["회의 자동 요약 · 액션 아이템 추출", "이메일 초안 자동 생성", "캘린더 최적화 제안"] },
    { name: "Word / Excel / PPT", items: ["Agent Mode — 다단계 반복 편집", "데이터 분석 · 차트 자동 생성", "보고서 초안 생성 (Anthropic Claude 기반)"] },
    { name: "AI 업무 침투", items: ["반복업무 AI 대체 경험 누적", "Before/After 시간 측정으로 효과 인식", "AI 친숙도 형성 → Layer 2 진입 준비"] },
  ];

  tools.forEach((t, i) => {
    const ty = 1.25 + i * 1.22;
    s.addShape(pres.shapes.RECTANGLE, {
      x: 0.55, y: ty, w: 0.07, h: 0.96,
      fill: { color: C.lgRed }, line: { color: C.lgRed }
    });
    s.addText(t.name, {
      x: 0.76, y: ty, w: 4.5, h: 0.34,
      fontSize: 13, bold: true, color: C.black,
      fontFace: "Arial", align: "left", margin: 0
    });
    t.items.forEach((item, j) => {
      s.addShape(pres.shapes.OVAL, {
        x: 0.8, y: ty + 0.42 + j * 0.22, w: 0.07, h: 0.07,
        fill: { color: C.gray2 }, line: { color: C.gray2 }
      });
      s.addText(item, {
        x: 0.94, y: ty + 0.37 + j * 0.22, w: 4.3, h: 0.26,
        fontSize: 11.5, color: C.gray1,
        fontFace: "Arial", align: "left", margin: 0
      });
    });
  });

  // 오른쪽: 핵심 인사이트 박스 2개
  s.addShape(pres.shapes.RECTANGLE, {
    x: 5.7, y: 1.25, w: 3.75, h: 1.5,
    fill: { color: C.lgRedL }, line: { color: C.lgRed, pt: 0.8 }
  });
  s.addText("행동 전염 원리", {
    x: 5.85, y: 1.3, w: 3.45, h: 0.34,
    fontSize: 12, bold: true, color: C.lgRed,
    fontFace: "Arial", align: "left", margin: 0
  });
  s.addText("주변에 AI 사용자가 있을 경우\n본인 사용 가능성 3배 높음\n→ 가시적 사용자 1명 먼저 만들기가 핵심", {
    x: 5.85, y: 1.65, w: 3.45, h: 0.96,
    fontSize: 11, color: C.gray1,
    fontFace: "Arial", align: "left", margin: 0
  });

  s.addShape(pres.shapes.RECTANGLE, {
    x: 5.7, y: 2.9, w: 3.75, h: 1.5,
    fill: { color: C.gray4 }, line: { color: C.gray3, pt: 0.5 }
  });
  s.addText("도입 전제 조건", {
    x: 5.85, y: 2.95, w: 3.45, h: 0.34,
    fontSize: 12, bold: true, color: C.navy,
    fontFace: "Arial", align: "left", margin: 0
  });
  s.addText("IT팀: M365 라이선스 수준 확인\nAgent Mode용 Anthropic 모델 활성화\n보안 정책 검토 (데이터 거버넌스)", {
    x: 5.85, y: 3.3, w: 3.45, h: 0.96,
    fontSize: 11, color: C.gray1,
    fontFace: "Arial", align: "left", margin: 0
  });
}

// ─────────────────────────────────────────────────────
// SLIDE 4: Layer 2 — 10주 스프린트 설계
// ─────────────────────────────────────────────────────
{
  const s = pres.addSlide();
  s.background = { color: C.white };

  addHeader(s,
    "10주 워크플로우 재설계 스프린트가 구성원을 사용자에서 설계자로 전환시킨다",
    "1인 1업무 선택 → 해부 → 실험 → 정제 → 확장 → 공유"
  );
  addFooter(s);

  // 5단계 타임라인
  const phases = [
    { wk: "W1–2", label: "해부", body: "업무 선택\n소요시간 측정\nAs-Is 분석", color: C.navy },
    { wk: "W3–4", label: "실험", body: "AI 첫 위임\n수정 패턴\n발견", color: C.navy },
    { wk: "W5–6", label: "정제", body: "프롬프트\n구체화\n효과 측정", color: "7A5C00" },
    { wk: "W7–8", label: "확장", body: "인접 업무\n적용\nTool 심화", color: "7A5C00" },
    { wk: "W9–10", label: "공유", body: "사례 문서화\nAX 쇼케이스\n발표", color: "4A1C6A" },
  ];

  // 타임라인 연결선
  s.addShape(pres.shapes.LINE, {
    x: 0.8, y: 2.05, w: 8.5, h: 0,
    line: { color: C.gray3, width: 1 }
  });

  phases.forEach((p, i) => {
    const cx = 0.8 + i * 1.75;
    // 원
    s.addShape(pres.shapes.OVAL, {
      x: cx + 0.5, y: 1.82, w: 0.46, h: 0.46,
      fill: { color: p.color }, line: { color: p.color }
    });
    s.addText(String(i + 1), {
      x: cx + 0.5, y: 1.82, w: 0.46, h: 0.46,
      fontSize: 13, bold: true, color: C.white,
      fontFace: "Arial", align: "center", valign: "middle"
    });
    // 주차
    s.addText(p.wk, {
      x: cx + 0.22, y: 1.5, w: 1.0, h: 0.28,
      fontSize: 9.5, color: p.color, bold: true,
      fontFace: "Arial", align: "center", margin: 0
    });
    // 단계명
    s.addText(p.label, {
      x: cx + 0.2, y: 2.34, w: 1.05, h: 0.32,
      fontSize: 13, bold: true, color: C.black,
      fontFace: "Arial", align: "center", margin: 0
    });
    // 설명 박스
    s.addShape(pres.shapes.RECTANGLE, {
      x: cx + 0.1, y: 2.72, w: 1.38, h: 1.82,
      fill: { color: C.gray4 }, line: { color: C.gray3, pt: 0.5 }
    });
    const lines = p.body.split("\n");
    lines.forEach((line, j) => {
      s.addText(line, {
        x: cx + 0.15, y: 2.8 + j * 0.54, w: 1.28, h: 0.46,
        fontSize: 11, color: C.gray1,
        fontFace: "Arial", align: "center", valign: "middle", margin: 0
      });
    });
  });

  // 하단 핵심 측정 지표
  s.addShape(pres.shapes.RECTANGLE, {
    x: 0.55, y: 4.72, w: 8.9, h: 0.38,
    fill: { color: C.lgRedL }, line: { color: C.lgRed, pt: 0.5 }
  });
  s.addText("측정 지표:  Before 소요시간  vs  After 소요시간  →  절감 시간 합산  =  생산성 10% 개선 산출 근거", {
    x: 0.7, y: 4.72, w: 8.6, h: 0.38,
    fontSize: 11, color: C.lgRed, bold: true,
    fontFace: "Arial", align: "left", valign: "middle", margin: 0
  });
}

// ─────────────────────────────────────────────────────
// SLIDE 5: Layer 3 — AX 내재화 확산
// ─────────────────────────────────────────────────────
{
  const s = pres.addSlide();
  s.background = { color: C.white };

  addHeader(s,
    "개인 재설계 사례가 팀 공유 자산이 될 때 AX 문화가 조직에 정착된다",
    "한 명의 가시적 성공 사례가 열 번의 교육보다 강력하다 — 행동 전염 연구"
  );
  addFooter(s, "Source: Irrational Labs AI Adoption Research (2025) / Frontiers in Org. Psych. (2026)");

  // 왼쪽 텍스트 + 오른쪽 표
  const items = [
    { title: "AX 쇼케이스 운영", body: "10주 스프린트 결과를 팀 전체에 공개 발표\nBefore/After 수치 공개로 행동 전염 유도\n분기 1회 → 연 4회 사례 누적" },
    { title: "팀 공통 Agent 개발", body: "개인 자동화를 팀 공유 프롬프트 라이브러리로 전환\nEXG 팀 공통 AI 워크플로우 자산 구축\n반복 재사용으로 효과 복리 증대" },
    { title: "AX 성숙도 측정", body: "Pulse Check 시스템과 연계한 정기 측정\n참여율·생산성·성숙도 3지표 분기 추적\n전사 AX 성숙도 평균 대비 +15% KPI 관리" },
  ];

  items.forEach((item, i) => {
    const ty = 1.25 + i * 1.22;
    s.addShape(pres.shapes.RECTANGLE, {
      x: 0.55, y: ty, w: 0.07, h: 0.96,
      fill: { color: "4A1C6A" }, line: { color: "4A1C6A" }
    });
    s.addText(item.title, {
      x: 0.76, y: ty, w: 4.5, h: 0.34,
      fontSize: 13, bold: true, color: C.black,
      fontFace: "Arial", align: "left", margin: 0
    });
    const lines = item.body.split("\n");
    lines.forEach((line, j) => {
      s.addShape(pres.shapes.OVAL, {
        x: 0.8, y: ty + 0.42 + j * 0.22, w: 0.07, h: 0.07,
        fill: { color: C.gray2 }, line: { color: C.gray2 }
      });
      s.addText(line, {
        x: 0.94, y: ty + 0.37 + j * 0.22, w: 4.3, h: 0.26,
        fontSize: 11.5, color: C.gray1,
        fontFace: "Arial", align: "left", margin: 0
      });
    });
